{"script":"cat << 'EOF' > count_peak_logins.sh
#!/usr/bin/env bash

# Usage: ./count_peak_logins.sh [logfile]
# Default logfile is server.log in the current directory.

logfile="${1:-server.log}"

# If the logfile does not exist, print 0 and exit.
if [ ! -f "$logfile" ]; then
  echo 0
  exit 0
fi

# Extract timestamps and count logins between 21:00 and 23:59 inclusive.
awk '
  {
    # Find the first HH:MM 24-hour timestamp in the line
    if (match($0, /([01][0-9]|2[0-3]):[0-5][0-9]/, m)) {
      split(m[0], t, ":");
      h = t[1] + 0;
      if (h >= 21 && h <= 23) {
        count++;
      }
    }
  }
  END {
    # Print only the integer count
    print count + 0;
  }
' "$logfile"
EOF

chmod +x count_peak_logins.sh

# Show the script content so the user can see it
cat count_peak_logins.sh"}

